parameters.functionCode:
// ─────────────────────────────────────────────────────────────
// STEP: Extract & Enrich Issue Data
// ─────────────────────────────────────────────────────────────
// This node reads the raw GitHub webhook payload and pulls out
// all the fields we need, then makes smart decisions about
// ticket type and priority based on the issue's labels.
// ─────────────────────────────────────────────────────────────

const issue = $json.body.issue;
const repo = $json.body.repository;

// --- Pull core fields from the GitHub issue ---
const title = issue.title;
const body = issue.body || 'No description provided.';
const issueUrl = issue.html_url;
const issueNumber = issue.number;
const reporterGitHub = issue.user.login;
const labels = issue.labels.map(l => l.name.toLowerCase());

// ─────────────────────────────────────────────────────────────
// LABEL → JIRA TICKET TYPE MAPPING
// Change these to match your own GitHub label conventions.
// Jira issue types: 'Bug', 'Story', 'Task', 'Epic'
// ─────────────────────────────────────────────────────────────
let jiraIssueType = 'Task'; // default
if (labels.includes('bug') || labels.includes('defect')) {
  jiraIssueType = 'Bug';
} else if (labels.includes('feature') || labels.includes('enhancement') || labels.includes('story')) {
  jiraIssueType = 'Story';
} else if (labels.includes('epic')) {
  jiraIssueType = 'Epic';
}

// ─────────────────────────────────────────────────────────────
// LABEL → JIRA PRIORITY MAPPING
// Jira priorities: 'Highest', 'High', 'Medium', 'Low', 'Lowest'
// ─────────────────────────────────────────────────────────────
let jiraPriority = 'Medium'; // default
if (labels.includes('critical') || labels.includes('urgent') || labels.includes('p0')) {
  jiraPriority = 'Highest';
} else if (labels.includes('high') || labels.includes('p1')) {
  jiraPriority = 'High';
} else if (labels.includes('low') || labels.includes('p3')) {
  jiraPriority = 'Low';
}

// ─────────────────────────────────────────────────────────────
// SKIP FLAG — labels that should NOT create a Jira ticket
// e.g. questions, documentation, duplicate reports
// ─────────────────────────────────────────────────────────────
const skipLabels = ['question', 'duplicate', 'wontfix', 'invalid', 'docs'];
const shouldSkip = labels.some(l => skipLabels.includes(l));

// Build a clean description for the Jira ticket
const jiraDescription = [
  `*Reported by:* ${reporterGitHub}`,
  `*GitHub Issue:* [#${issueNumber} - ${title}|${issueUrl}]`,
  `*Repository:* ${repo.full_name}`,
  '',
  '---',
  '',
  '*Original Description:*',
  body
].join('\n');

return [{
  json: {
    title,
    jiraDescription,
    jiraIssueType,
    jiraPriority,
    issueUrl,
    issueNumber,
    reporterGitHub,
    repoFullName: repo.full_name,
    repoOwner: repo.owner.login,
    repoName: repo.name,
    labels,
    shouldSkip
  }
}];

